SELECT COUNT(DISTINCT user_id) AS total_users
FROM access_logs
WHERE access_date >= '2022-01-01';

SELECT timestamp_value, timestamp_type, precision
FROM timestamps
WHERE created_at > '2022-04-01T00:00:00Z';

SELECT date_granularity, COUNT(date_id) AS number_of_dates, MAX(created_at) AS latest_creation_date, MIN(created_at) AS earliest_creation_date
FROM dates
GROUP BY date_granularity;

SELECT date_value, date_type, date_granularity, timestamp
FROM dates
WHERE created_by = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');

SELECT COUNT(conversion_id) AS successful_conversion_count
FROM date_time_conversions
WHERE conversion_result = 'success';

SELECT MAX(precision) AS max_precision
FROM (
    SELECT precision FROM datetimes
    UNION ALL
    SELECT precision FROM timestamps
) AS combined_precision;

SELECT datetime_value 
FROM datetimes 
WHERE datetime_type = 'INSTANT';

SELECT precision, COUNT(*) AS precision_count
FROM timestamps
GROUP BY precision;

SELECT comparison_id, comparison_result
FROM date_time_comparisons
WHERE comparison_result = 'later';

SELECT comparison_result, COUNT(comparison_result) AS comparison_count
FROM date_time_comparisons
GROUP BY comparison_result;

SELECT granularity_name
FROM date_time_granularities
WHERE granularity_description LIKE '%level%';

SELECT COUNT(*) AS total_earlier_comparisons
FROM date_time_comparisons
WHERE comparison_result = 'earlier';
